3	const PROCESSING_FEE = 5;
4	const FIRST_INSURANCE_SURCHARGE = 0.1;
5	const CURSED_SURCHARGE_RATE = 0.5;
6	const HIGH_ENCHANTMENT_SURCHARGE_RATE = 0.3;
7	const HIGH_ENCHANTMENT_THRESHOLD = 5;
8	
9	const BASE_PREMIUMS: Record<string, number> = {
10	  sword: 100,
11	  amulet: 60,
12	  staff: 80,
13	  potion: 40,
14	  rune: 25,
15	  moonstone: 25,
16	};
17	
18	type Item = { type: string; cursed?: boolean; enchantment?: number };
19	type Step = { op: string; items: Item[] };
20	type Customer = { yearsWithMHPCO?: number };
21	type Scenario = { steps: Step[]; customer?: Customer };
22	
23	const COMPONENT_TYPES = new Set(["rune", "moonstone"]);
24	const BLOCK_SIZE = 3;
25	const BLOCK_BASE_PREMIUM = 60;
26	
27	const basePremiumForType = (type: string): number => BASE_PREMIUMS[type] ?? 0;
28	
29	const itemBasePremium = (item: Item): number => basePremiumForType(item.type);
30	
31	const isComponent = (item: Item): boolean => COMPONENT_TYPES.has(item.type);
32	
33	const countByType = (items: Item[]): Map<string, number> => {
34	  const counts = new Map<string, number>();
35	  for (const item of items) {
36	    counts.set(item.type, (counts.get(item.type) ?? 0) + 1);
37	  }
38	  return counts;
39	};
40	
41	const componentGroupPremium = (type: string, count: number): number =>
42	  count === BLOCK_SIZE ? BLOCK_BASE_PREMIUM : count * basePremiumForType(type);
43	
44	const sumItemBasePremiums = (items: Item[]): number => {
45	  const nonComponents = items.filter((item) => !isComponent(item));
46	  const components = items.filter(isComponent);
47	  const nonComponentsTotal = nonComponents.reduce(
48	    (sum, item) => sum + itemBasePremium(item),
49	    0,
50	  );
51	  const componentsTotal = Array.from(countByType(components)).reduce(
52	    (sum, [type, count]) => sum + componentGroupPremium(type, count),
53	    0,
54	  );
55	  return nonComponentsTotal + componentsTotal;
56	};
57	
58	const isCursed = (item: Item): boolean => item.cursed === true;
59	
60	const isHighlyEnchanted = (item: Item): boolean =>
61	  (item.enchantment ?? 0) >= HIGH_ENCHANTMENT_THRESHOLD;
62	
63	const cursedSurcharge = (item: Item, base: number): number =>
64	  isCursed(item) ? base * CURSED_SURCHARGE_RATE : 0;
65	
66	const highEnchantmentSurcharge = (item: Item, base: number): number =>
67	  isHighlyEnchanted(item) ? base * HIGH_ENCHANTMENT_SURCHARGE_RATE : 0;
68	
69	const itemSurcharge = (item: Item): number => {
70	  const base = itemBasePremium(item);
71	  return cursedSurcharge(item, base) + highEnchantmentSurcharge(item, base);
72	};
73	
74	const sumItemSurcharges = (items: Item[]): number =>
75	  items.reduce((sum, item) => sum + itemSurcharge(item), 0);
76	
77	const LOYALTY_DISCOUNT_RATE = 0.2;
78	const LOYALTY_THRESHOLD_YEARS = 2;
79	
80	const isLongStandingCustomer = (customer: Customer | undefined): boolean =>
81	  (customer?.yearsWithMHPCO ?? 0) >= LOYALTY_THRESHOLD_YEARS;
82	
83	const loyaltyDiscountFor = (customer: Customer | undefined, base: number): number =>
84	  isLongStandingCustomer(customer) ? base * LOYALTY_DISCOUNT_RATE : 0;
85	
86	export function runScenario(scenario: unknown): { results: { premium: number }[] } {
87	  const s = scenario as Scenario;
88	  const step = s.steps[0];
89	  const itemsBase = sumItemBasePremiums(step.items);
90	  const itemSurcharges = sumItemSurcharges(step.items);
91	  const firstInsurance = itemsBase * FIRST_INSURANCE_SURCHARGE;
92	  const loyaltyDiscount = loyaltyDiscountFor(s.customer, itemsBase);
93	  const premium = Math.ceil(itemsBase + itemSurcharges + firstInsurance - loyaltyDiscount + PROCESSING_FEE);
94	  return { results: [{ premium }] };
95	}
