const FOLLOW_UP_DISCOUNT_RATE = 0.15;

export function runScenario(scenario: unknown): { results: { premium: number }[] } {
  const s = scenario as Scenario;
  const results: { premium: number }[] = [];
  let priorQuoteCount = 0;
  for (const step of s.steps) {
    const itemsBase = sumItemBasePremiums(step.items);
    const itemSurcharges = sumItemSurcharges(step.items);
    const firstInsurance = itemsBase * FIRST_INSURANCE_SURCHARGE;
    const loyaltyDiscount = loyaltyDiscountFor(s.customer, itemsBase);
    const followUpDiscount = priorQuoteCount > 0 ? itemsBase * FOLLOW_UP_DISCOUNT_RATE : 0;
    const premium = Math.ceil(itemsBase + itemSurcharges + firstInsurance - loyaltyDiscount - followUpDiscount + PROCESSING_FEE);
    results.push({ premium });
    priorQuoteCount += 1;
  }
  return { results };
}
